    67→export const ChatClient = ({
    68→  projectId,
    69→  isOpen,
    70→  setIsOpen,
    71→}: {
    72→  projectId: string;
    73→  isOpen: boolean;
    74→  setIsOpen: (isOpen: boolean) => void;
    75→}) => {
    76→  const { refreshCredits } = useCredits();
