     2→title: Type-Safe useChat with Agents
     3→description: Build end-to-end type-safe agents by inferring UIMessage types from your agent definition.
     4→---
     5→
     6→# Type-Safe useChat with Agents
     7→
     8→Build end-to-end type-safe agents by inferring `UIMessage` types from your agent definition for type-safe UI rendering with `useChat`.
     9→
    10→## Recommended Structure
    11→
    12→```
    13→lib/
    14→  agents/
    15→    my-agent.ts       # Agent definition + type export
    16→  tools/
    17→    weather-tool.ts   # Individual tool definitions
    18→    calculator-tool.ts
    19→```
    20→
    21→## Define Tools
    22→
    23→```ts
    24→// lib/tools/weather-tool.ts
    25→import { tool } from 'ai';
    26→import { z } from 'zod';
    27→
    28→export const weatherTool = tool({
    29→  description: 'Get current weather for a location',
    30→  inputSchema: z.object({
    31→    location: z.string().describe('City name'),
    32→  }),
    33→  execute: async ({ location }) => {
    34→    return { temperature: 72, condition: 'sunny', location };
    35→  },
    36→});
    37→```
    38→
    39→## Define Agent and Export Type
    40→
    41→```ts
    42→// lib/agents/my-agent.ts
    43→import { ToolLoopAgent, InferAgentUIMessage } from 'ai';
    44→import { weatherTool } from '../tools/weather-tool';
    45→import { calculatorTool } from '../tools/calculator-tool';
    46→
    47→export const myAgent = new ToolLoopAgent({
    48→  model: 'anthropic/claude-sonnet-4',
    49→  instructions: 'You are a helpful assistant.',
    50→  tools: {
    51→    weather: weatherTool,
    52→    calculator: calculatorTool,
    53→  },
    54→});
    55→
    56→// Infer the UIMessage type from the agent
    57→export type MyAgentUIMessage = InferAgentUIMessage<typeof myAgent>;
    58→```
    59→
    60→### With Custom Metadata
    61→
    62→```ts
    63→// lib/agents/my-agent.ts
    64→import { z } from 'zod';
    65→
    66→const metadataSchema = z.object({
    67→  createdAt: z.number(),
    68→  model: z.string().optional(),
    69→});
    70→
    71→type MyMetadata = z.infer<typeof metadataSchema>;
    72→
    73→export type MyAgentUIMessage = InferAgentUIMessage<typeof myAgent, MyMetadata>;
    74→```
    75→
    76→## Use with `useChat`
    77→
    78→```tsx
    79→// app/chat.tsx
    80→import { useChat } from '@ai-sdk/react';
    81→import type { MyAgentUIMessage } from '@/lib/agents/my-agent';
    82→
    83→export function Chat() {
    84→  const { messages } = useChat<MyAgentUIMessage>();
    85→
    86→  return (
    87→    <div>
    88→      {messages.map(message => (
    89→        <Message key={message.id} message={message} />
    90→      ))}
    91→    </div>
    92→  );
    93→}
    94→```
    95→
    96→## Rendering Parts with Type Safety
    97→
    98→Tool parts are typed as `tool-{toolName}` based on your agent's tools:
    99→
   100→```tsx
   101→function Message({ message }: { message: MyAgentUIMessage }) {
   102→  return (
   103→    <div>
   104→      {message.parts.map((part, i) => {
   105→        switch (part.type) {
   106→          case 'text':
   107→            return <p key={i}>{part.text}</p>;
   108→
   109→          case 'tool-weather':
   110→            // part.input and part.output are fully typed
   111→            if (part.state === 'output-available') {
   112→              return (
   113→                <div key={i}>
   114→                  Weather in {part.input.location}: {part.output.temperature}F
   115→                </div>
   116→              );
   117→            }
   118→            return <div key={i}>Loading weather...</div>;
   119→
   120→          case 'tool-calculator':
   121→            // TypeScript knows this is the calculator tool
   122→            return <div key={i}>Calculating...</div>;
   123→
   124→          default:
   125→            return null;
   126→        }
   127→      })}
   128→    </div>
   129→  );
   130→}
   131→```
   132→
   133→The `part.type` discriminant narrows the type, giving you autocomplete and type checking for `input` and `output` based on each tool's schema.
   134→
   135→## Splitting Tool Rendering into Components
   136→
   137→When rendering many tools, you may want to split each tool into its own component. Use `UIToolInvocation<TOOL>` to derive a typed invocation from your tool and export it alongside the tool definition:
   138→
   139→```ts
   140→// lib/tools/weather-tool.ts
   141→import { tool, UIToolInvocation } from 'ai';
   142→import { z } from 'zod';
   143→
   144→export const weatherTool = tool({
   145→  description: 'Get current weather for a location',
   146→  inputSchema: z.object({
   147→    location: z.string().describe('City name'),
   148→  }),
   149→  execute: async ({ location }) => {
   150→    return { temperature: 72, condition: 'sunny', location };
   151→  },
   152→});
   153→
   154→// Export the invocation type for use in UI components
   155→export type WeatherToolInvocation = UIToolInvocation<typeof weatherTool>;
   156→```
   157→
   158→Then import only the type in your component:
   159→
   160→```tsx
   161→// components/weather-tool.tsx
   162→import type { WeatherToolInvocation } from '@/lib/tools/weather-tool';
   163→
   164→export function WeatherToolComponent({
   165→  invocation,
   166→}: {
   167→  invocation: WeatherToolInvocation;
   168→}) {
   169→  // invocation.input and invocation.output are fully typed
   170→  if (invocation.state === 'output-available') {
   171→    return (
   172→      <div>
   173→        Weather in {invocation.input.location}: {invocation.output.temperature}F
   174→      </div>
   175→    );
   176→  }
   177→  return <div>Loading weather for {invocation.input?.location}...</div>;
   178→}
   179→```
   180→
   181→Use the component in your message renderer:
   182→
   183→```tsx
   184→function Message({ message }: { message: MyAgentUIMessage }) {
   185→  return (
   186→    <div>
   187→      {message.parts.map((part, i) => {
   188→        switch (part.type) {
   189→          case 'text':
   190→            return <p key={i}>{part.text}</p>;
   191→          case 'tool-weather':
   192→            return <WeatherToolComponent key={i} invocation={part} />;
   193→          case 'tool-calculator':
   194→            return <CalculatorToolComponent key={i} invocation={part} />;
   195→          default:
   196→            return null;
   197→        }
   198→      })}
   199→    </div>
   200→  );
   201→}
   202→```
   203→
   204→This approach keeps your tool rendering logic organized while maintaining full type safety, without needing to import the tool implementation into your UI components.
   205→

